import boto3
import json
import uuid
from datetime import datetime
from typing import Dict, List, Optional, Any
import hashlib


class SQSPublisher:
    def __init__(self, queue_url: str, region_name: str = 'us-east-1'):
        self.queue_url = queue_url
        self.sqs_client = boto3.client('sqs', region_name=region_name)
        
    def publish_user_data(self, user_data: Dict[str, Any], 
                         message_group_id: Optional[str] = None,
                         deduplication_id: Optional[str] = None) -> Dict[str, Any]:
        message_body = {
            'message_id': str(uuid.uuid4()),
            'timestamp': datetime.utcnow().isoformat(),
            'user_data': user_data
        }
        
        params = {
            'QueueUrl': self.queue_url,
            'MessageBody': json.dumps(message_body)
        }
        
        if message_group_id:
            params['MessageGroupId'] = message_group_id
            
        if deduplication_id:
            params['MessageDeduplicationId'] = deduplication_id
        else:
            content_hash = hashlib.sha256(
                json.dumps(user_data, sort_keys=True).encode()
            ).hexdigest()
            params['MessageDeduplicationId'] = content_hash
        
        response = self.sqs_client.send_message(**params)
        return response
    
    def publish_batch(self, user_data_list: List[Dict[str, Any]], 
                     message_group_id: Optional[str] = None) -> Dict[str, Any]:
        entries = []
        
        for idx, user_data in enumerate(user_data_list):
            message_body = {
                'message_id': str(uuid.uuid4()),
                'timestamp': datetime.utcnow().isoformat(),
                'user_data': user_data
            }
            
            entry = {
                'Id': str(idx),
                'MessageBody': json.dumps(message_body)
            }
            
            if message_group_id:
                entry['MessageGroupId'] = message_group_id
            
            content_hash = hashlib.sha256(
                json.dumps(user_data, sort_keys=True).encode()
            ).hexdigest()
            entry['MessageDeduplicationId'] = content_hash
            
            entries.append(entry)
        
        response = self.sqs_client.send_message_batch(
            QueueUrl=self.queue_url,
            Entries=entries
        )
        return response
    
    def publish_with_attributes(self, user_data: Dict[str, Any],
                               attributes: Optional[Dict[str, Any]] = None,
                               message_group_id: Optional[str] = None) -> Dict[str, Any]:
        message_body = {
            'message_id': str(uuid.uuid4()),
            'timestamp': datetime.utcnow().isoformat(),
            'user_data': user_data
        }
        
        params = {
            'QueueUrl': self.queue_url,
            'MessageBody': json.dumps(message_body)
        }
        
        if attributes:
            message_attributes = {}
            for key, value in attributes.items():
                if isinstance(value, str):
                    message_attributes[key] = {
                        'StringValue': value,
                        'DataType': 'String'
                    }
                elif isinstance(value, int):
                    message_attributes[key] = {
                        'StringValue': str(value),
                        'DataType': 'Number'
                    }
            params['MessageAttributes'] = message_attributes
        
        if message_group_id:
            params['MessageGroupId'] = message_group_id
        
        content_hash = hashlib.sha256(
            json.dumps(user_data, sort_keys=True).encode()
        ).hexdigest()
        params['MessageDeduplicationId'] = content_hash
        
        response = self.sqs_client.send_message(**params)
        return response


class UserDataMessage:
    def __init__(self, user_id: str, email: str, phone_number: str,
                 first_name: str, last_name: str, address: Dict[str, str],
                 additional_data: Optional[Dict[str, Any]] = None):
        self.user_id = user_id
        self.email = email
        self.phone_number = phone_number
        self.first_name = first_name
        self.last_name = last_name
        self.address = address
        self.additional_data = additional_data or {}
    
    def to_dict(self) -> Dict[str, Any]:
        return {
            'user_id': self.user_id,
            'pii': {
                'email': self.email,
                'phone_number': self.phone_number,
                'first_name': self.first_name,
                'last_name': self.last_name,
                'address': self.address
            },
            'additional_data': self.additional_data
        }


class PIIDataPublisher:
    def __init__(self, queue_url: str, region_name: str = 'us-east-1'):
        self.publisher = SQSPublisher(queue_url, region_name)
    
    def publish_user_registration(self, user_message: UserDataMessage) -> Dict[str, Any]:
        user_data = user_message.to_dict()
        attributes = {
            'event_type': 'user_registration',
            'user_id': user_message.user_id
        }
        return self.publisher.publish_with_attributes(
            user_data, 
            attributes,
            message_group_id='user_events'
        )
    
    def publish_user_update(self, user_message: UserDataMessage) -> Dict[str, Any]:
        user_data = user_message.to_dict()
        attributes = {
            'event_type': 'user_update',
            'user_id': user_message.user_id
        }
        return self.publisher.publish_with_attributes(
            user_data,
            attributes,
            message_group_id='user_events'
        )
    
    def publish_bulk_users(self, user_messages: List[UserDataMessage]) -> Dict[str, Any]:
        user_data_list = [msg.to_dict() for msg in user_messages]
        return self.publisher.publish_batch(user_data_list, message_group_id='bulk_user_events')


